import { useUserSession } from "@/hooks/use-user-session";
import { getRouteApi } from "@tanstack/react-router";
import {
  Button,
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  Sidebar,
  SidebarFooter,
  SidebarHeader,
  cn,
} from "@workspace/ui";
import { Check, ChevronsUpDown } from "lucide-react";

const authedRouteApi = getRouteApi("/_authed");

export function AppSidebar({ className }: { className?: string }) {
  const { tenants, currentTenant } = authedRouteApi.useLoaderData();
  const { setSelectedTenantId, isPending } = useUserSession();

  return (
    <Sidebar className={cn("border-sidebar-border", className)} collapsible="icon">
      <SidebarHeader>
        {tenants.length === 0 ? (
          <p className="px-2 text-muted-foreground text-sm leading-snug">
            No tenants yet
          </p>
        ) : (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                aria-label="Select tenant"
                className="h-10 w-full justify-between gap-2 px-2 font-normal"
                disabled={isPending}
                variant="outline"
              >
                <span className="truncate text-left text-sm">
                  {currentTenant?.name ?? "Select tenant"}
                </span>
                <ChevronsUpDown className="size-4 shrink-0 opacity-60" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="start" className="w-[var(--radix-dropdown-menu-trigger-width)] min-w-56">
              {tenants.map((tenant) => (
                <DropdownMenuItem
                  className="cursor-pointer gap-2"
                  disabled={isPending}
                  key={tenant.id}
                  onSelect={() => {
                    void setSelectedTenantId(tenant.id);
                  }}
                >
                  <span className="flex-1 truncate">{tenant.name}</span>
                  {currentTenant?.id === tenant.id ? (
                    <Check className="size-4 shrink-0" />
                  ) : (
                    <span className="size-4 shrink-0" />
                  )}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        )}
      </SidebarHeader>
      <SidebarFooter />
    </Sidebar>
  );
}

