import { AppSidebar } from "@/components/app-sidebar";
import { createFileRoute, Outlet, redirect } from "@tanstack/react-router";
import { SidebarInset, SidebarProvider } from "@workspace/ui";
import { getAppBootstrapData } from "../server/app-bootstrap";

export const Route = createFileRoute("/_authed")({
  loader: async ({ location }) => {
    const appBootstrap = await getAppBootstrapData();

    const onOrganizationsNewRoute = location.pathname === "/organizations/new";

    if (appBootstrap.user && !appBootstrap.tenant && !onOrganizationsNewRoute) {
      throw redirect({ to: "/organizations/new" });
    }

    return appBootstrap;
  },
  component: AuthedLayout,
});

function AuthedLayout() {
  return (
    <SidebarProvider defaultCollapsed={false}>
      <div className="flex h-screen w-full overflow-hidden bg-background">
        <AppSidebar />
        <SidebarInset className="flex min-h-0 flex-1 flex-col overflow-hidden">
          <div className="min-h-0 flex-1 overflow-y-auto bg-muted">
            <Outlet />
          </div>
        </SidebarInset>
      </div>
    </SidebarProvider>
  );
}

